export interface IconListProps {
  title: string
  items: {
    title: string
    icon: string
  }[]
}

import { icons } from 'lucide-react'

import { Icon } from '@/components/flx/blocks/shared/dynamic-icon/dynamic-icon'

import type { IconListProps } from './types'

export function IconList({ title, items }: Readonly<IconListProps>) {
  return (
    <div className="grid w-full">
      <h2 className="mb-8 text-2xl font-bold">{title}</h2>
      <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-3">
        {items.map((item, index) => (
          <div className="flex items-center gap-3" key={item.title + index}>
            <Icon
              name={item.icon as keyof typeof icons}
              className="text-primary size-4 flex-shrink-0"
            />
            <h3 className="text-base font-medium">{item.title}</h3>
          </div>
        ))}
      </div>
    </div>
  )
}

import { iconListDefaultProps } from './defaults'
import { IconList } from './icon-list'

export function IconListUsage() {
  return <IconList {...iconListDefaultProps} />
}
